import React from 'react'
import { FlutterWaveButton, closePaymentModal } from 'flutterwave-react-v3'
import PropTypes from 'prop-types'

const FlutterPayment = ({ amount, email, phone, fullname }) => {
  const config = {
    public_key: 'FLWPUBK-**************************-X',
    tx_ref: Date.now(),
    amount: amount,
    currency: 'NGN',
    payment_options: 'card,mobilemoney,ussd',
    customer: {
      email: email,
      phonenumber: phone,
      name: fullname,
    },
    customizations: {
      title: 'My store',
      description: 'Payment for Transcript',
      logo: 'https://st2.depositphotos.com/4403291/7418/v/450/depositphotos_74189661-stock-illustration-online-shop-log.jpg',
    },
  }

  const fwConfig = {
    ...config,
    text: 'Pay with Flutterwave!',
    callback: (response) => {
      console.log(response)
      closePaymentModal()
    },
    onClose: () => {},
  }

  return (
    <div>
      <img
        style={{ width: '20%' }}
        className="text-align:left"
        src="https://images.squarespace-cdn.com/content/v1/5355ed0ae4b0753f93e22adc/1644581655983-SQO6EU0EJVZUR46UMEXP/Flutterwave+Logo.png?format=500w"
        alt="logo"
      />
      <FlutterWaveButton {...fwConfig} className="btn btn-warning" />
    </div>
  )
}

FlutterPayment.propTypes = {
  amount: PropTypes.any,
  email: PropTypes.string,
  phone: PropTypes.string,
  fullname: PropTypes.string,
}

export default FlutterPayment
